import React from "react";
import WeatherOverlay from "./WeatherOverlay";

export default function WeatherApp() {
  const weatherCondition = "rain"; // Replace with real-time data
  const isDaytime = false;         // Replace with actual day/night logic

  return (
    <div className="relative flex flex-col min-h-screen overflow-hidden bg-black">
      {/* Weather Background Overlay */}
      <WeatherOverlay
        weatherCondition={weatherCondition}
        isDaytime={isDaytime}
      />

      {/* Header */}
      <div className="text-center py-6 z-10">
        <h1 className="text-4xl font-bold text-white drop-shadow-glow">
          Today in <span className="text-purple-400">Atlanta</span>
        </h1>
        <p className="text-lg text-white/80 mt-1 capitalize drop-shadow-glow">
          {weatherCondition}
        </p>
      </div>

      {/* Glowing Numbers */}
      <div className="flex-1 flex flex-col items-center justify-center space-y-6 z-10 pb-24">
        <div className="text-6xl font-bold text-black-300 drop-shadow-purple">
          36.2°C
        </div>
        <div className="text-3xl font-semibold text-black-300 drop-shadow-purple">
          Humidity: 70%
        </div>
        <div className="text-3xl font-semibold text-purple-300 drop-shadow-purple">
          Wind: 12 km/h
        </div>
        <div className="text-3xl font-semibold text-purple-300 drop-shadow-purple">
          UV Index: 5
        </div>
      </div>

      {/* Bottom Navigation Bar */}
      <div className="h-20 fixed bottom-0 left-0 w-full bg-white/30 backdrop-blur-md border-t border-white/40 shadow-lg z-10 flex items-center justify-around rounded-t-2xl">
        {[
          { icon: "🌤", label: "Forecast" },
          { icon: "📡", label: "Radar" },
          { icon: "💬", label: "Community" },
          { icon: "🤖", label: "Weathy" },
        ].map((tab, idx) => (
          <button
            key={idx}
            className="flex flex-col items-center text-gray-800 hover:text-purple-500 transition duration-300"
          >
            <span className="text-xl">{tab.icon}</span>
            <span className="text-xs">{tab.label}</span>
          </button>
        ))}
      </div>
    </div>
  );
}
